using CertDesk.Models; using CertDesk.Services;
namespace CertDesk.Forms;
public sealed class EmployeeEditForm:Form
{ public EmployeeEditForm(Employee e,EmployeeService service){Text="Сотрудник"; StartPosition=FormStartPosition.CenterParent; Width=390; Height=520; var p=new FlowLayoutPanel{Dock=DockStyle.Fill,FlowDirection=FlowDirection.TopDown,Padding=new Padding(16)}; TextBox fn=Ui.TextBox(), pos=Ui.TextBox(), dep=Ui.TextBox(), mail=Ui.TextBox(), phone=Ui.TextBox(), snils=Ui.TextBox(), inn=Ui.TextBox(); CheckBox active=new(){Text="Активен",Checked=e.IsActive}; fn.Text=e.FullName; pos.Text=e.Position; dep.Text=e.Department; mail.Text=e.Email; phone.Text=e.Phone; snils.Text=e.Snils; inn.Text=e.Inn; foreach(var x in new[]{("ФИО",fn),("Должность",pos),("Подразделение",dep),("Email",mail),("Телефон",phone),("СНИЛС",snils),("ИНН",inn)}){p.Controls.Add(Ui.Label(x.Item1));p.Controls.Add(x.Item2);} var save=Ui.Button("Сохранить"); p.Controls.Add(active); p.Controls.Add(save); Controls.Add(p); save.Click+=(_,_)=>{try{e.FullName=fn.Text;e.Position=pos.Text;e.Department=dep.Text;e.Email=mail.Text;e.Phone=phone.Text;e.Snils=snils.Text;e.Inn=inn.Text;e.IsActive=active.Checked; service.Save(e); DialogResult=DialogResult.OK; Close();}catch(Exception ex){Ui.Error(ex);}};}
}
